<?php require_once __DIR__.'/../inc/bootstrap.php'; $rows=[]; $up=0; $down=0; foreach(services_default() as $s){ $st=http_check($s['url']); if($st['ok']) $up++; else $down++; $rows[]=['name'=>$s['name'],'url'=>$s['url'],'status'=>$st]; } ?>
<div class="stack" data-page-version="<?= h(jarvis_file_version(__FILE__)) ?>"><div class="grid"><div class="kpi"><div class="label">Services</div><div class="value"><?= h(count($rows)) ?></div></div><div class="kpi"><div class="label">UP</div><div class="value"><?= h($up) ?></div></div><div class="kpi"><div class="label">DOWN</div><div class="value"><?= h($down) ?></div></div></div><div class="card"><table><thead><tr><th>service</th><th>url</th><th>statut</th><th>http</th><th>latence</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= h($r['name']) ?></td><td><code><?= h($r['url']) ?></code></td><td><span class="status <?= $r['status']['ok']?'up':'down' ?>"><?= $r['status']['ok']?'UP':'DOWN' ?></span></td><td><?= h((string)$r['status']['code']) ?></td><td><?= h((string)$r['status']['ms']) ?> ms</td></tr><?php endforeach; ?></tbody></table></div></div>
